.bg-preview.active{display:block}.bg-preview img{width:100%;height:100%;object-fit:cover}
.bg-preview-label{position:absolute;bottom:0;left:0;right:0;padding:3px 8px;font-size:.65rem;color:rgba(255,255,255,.8);background:linear-gradient(transparent,rgba(0,0,0,.6));font-family:var(--font-cn);letter-spacing:.04em}
.bg-theme-picker{display:none;padding:0 10px 6px}.bg-theme-picker.active{display:block}
.bg-theme-title{font-size:.68rem;color:var(--text-muted);margin-bottom:4px;font-family:var(--font-cn);letter-spacing:.04em}
.bg-theme-options{display:grid;grid-template-columns:repeat(4,1fr);gap:4px}
.bg-theme-opt{padding:5px 0;border-radius:var(--radius-sm);border:1px solid var(--border-glass);background:var(--cell-bg);color:var(--text-secondary);font-size:.7rem;cursor:pointer;font-family:var(--font-cn);transition:var(--transition);letter-spacing:.03em;text-align:center}
.bg-theme-opt:hover{background:var(--cell-hover);color:var(--text-primary);border-color:var(--border-glass-hover)}
.bg-theme-opt.selected{background:var(--accent-glow);color:var(--accent-light);border-color:rgba(249,188,96,.4)}
.site-footer{text-align:center;padding:32px 0 24px;font-size:.78rem;color:var(--text-muted);font-family:var(--font-cn);letter-spacing:.04em}
.site-footer a{color:var(--text-muted);text-decoration:none;transition:color .2s ease}
[data-theme="light"] .site-footer a:hover{color:#001e1d}[data-theme="dark"] .site-footer a:hover{color:#fffffe}
.export-options{display:flex;flex-direction:column;gap:12px}
.export-option{display:flex;align-items:flex-start;gap:12px;padding:14px;border:1px solid var(--border-glass);border-radius:var(--radius-md);cursor:pointer;transition:var(--transition);background:transparent}
.export-option:hover{border-color:var(--border-glass-hover);background:var(--cell-hover)}
.export-option input[type="radio"]{margin-top:4px;accent-color:var(--accent)}
.export-title{font-weight:600;font-size:.95rem;margin-bottom:4px;font-family:var(--font-cn)}
.export-desc{font-size:.8rem;color:var(--text-muted);font-family:var(--font-cn)}
.export-limit{font-size:.75rem;color:var(--text-muted);margin-top:16px;font-family:var(--font-cn);text-align:center}
@media(max-width:768px){.sidebar{transform:translateX(-100%);transition:transform .3s ease;z-index:100}.sidebar.open{transform:translateX(0)}.main{margin-left:0;padding:16px 12px 0}.mobile-menu-btn{display:block}.bookmarks-grid{grid-template-columns:repeat(auto-fill,minmax(max(140px,calc((100% - 10px)/4)),1fr));gap:8px}.group{padding:12px}.group .drag-handle{left:4px;top:4px;transform:none}.modal{padding:24px;margin:12px}}
@media(max-width:640px){.bookmarks-grid{grid-template-columns:repeat(auto-fill,minmax(max(120px,calc((100% - 8px)/3)),1fr));gap:8px}}
@media(max-width:480px){.bookmarks-grid{grid-template-columns:repeat(2,1fr);gap:8px}.bookmark-card{padding:8px 10px;min-height:52px}.bookmark-favicon{width:20px;height:20px}.bookmark-favicon img{width:14px;height:14px}.bookmark-name{font-size:.8rem}.bookmark-desc{font-size:.65rem;margin-left:28px}}
@media(max-width:360px){.bookmarks-grid{grid-template-columns:1fr;gap:8px}.main{padding:12px 10px 0}}
</style></head><body <?=$adminMode?'class="admin-mode"':''?>><div class="bg-mesh"></div><div class="bg-noise"></div><div class="bg-ghibli" id="bgG"><img id="bgI" src="" alt=""></div><button class="mobile-menu-btn" onclick="document.getElementById('sb').classList.toggle('open')"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><line x1="3" y1="6" x2="21" y2="6"/><line x1="3" y1="12" x2="21" y2="12"/><line x1="3" y1="18" x2="21" y2="18"/></svg></button><div class="layout"><aside class="sidebar" id="sb"><div class="sidebar-logo"><div class="sidebar-logo-text"><?=esc($data['siteName'])?></div></div><div class="sidebar-clock"><div class="clock" id="clk">00:00</div><div class="clock-date" id="clkD"></div></div><nav class="sidebar-nav" id="sNav"><?php foreach($data['groups'] as $gi=>$g):?><button class="nav-item" onclick="sG('<?=esc($g['id'])?>')"><span class="nav-item-icon nc-<?=$gi%6?>"><?=esc($g['emoji'])?></span><span class="nav-item-name"><?=esc($g['name'])?></span><span class="nav-item-count"><?=count($g['bookmarks'])?></span></button><?php endforeach;?><button class="nav-add-group admin-only" onclick="oGM()"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg>添加分组</button></nav><div class="bg-preview" id="bgP" onclick="tBg()"><img id="bgPI" src="" alt=""><div class="bg-preview-label" id="bgPL">乡村 · 日间</div></div><div class="bg-theme-picker" id="bgTP"><div class="bg-theme-title">选择背景风格</div><div class="bg-theme-options" id="bgTO"></div></div><div class="sidebar-footer"><div class="sidebar-footer-row"><button class="sidebar-btn" onclick="tT()"><div class="theme-toggle"><svg class="sun-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="5"/><line x1="12" y1="1" x2="12" y2="3"/><line x1="12" y1="21" x2="12" y2="23"/><line x1="4.22" y1="4.22" x2="5.64" y2="5.64"/><line x1="18.36" y1="18.36" x2="19.78" y2="19.78"/><line x1="1" y1="12" x2="3" y2="12"/><line x1="21" y1="12" x2="23" y2="12"/><line x1="4.22" y1="19.78" x2="5.64" y2="18.36"/><line x1="18.36" y1="5.64" x2="19.78" y2="4.22"/></svg><svg class="moon-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M21 12.79A9 9 0 1111.21 3 7 7 0 0021 12.79z"/></svg></div><span id="tL">日间模式</span></button><button class="sidebar-btn" onclick="tBg()" id="bgB"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="3" y="3" width="18" height="18" rx="2"/><circle cx="8.5" cy="8.5" r="1.5"/><path d="M21 15l-5-5L5 21"/></svg><span id="bgL">背景</span></button></div><div class="sidebar-footer-row admin-only"><button class="sidebar-btn" onclick="oEM()"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M21 15v4a2 2 0 01-2 2H5a2 2 0 01-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>数据导出</button><form method="POST" action="nav-api.php?action=logout" style="width:100%"><button type="submit" class="sidebar-btn"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M9 21H5a2 2 0 01-2-2V5a2 2 0 012-2h4"/><polyline points="16 17 21 12 16 7"/><line x1="21" y1="12" x2="9" y2="12"/></svg>退出管理</button></form></div><button class="sidebar-btn guest-only" onclick="oLM()"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M15 3h4a2 2 0 012 2v14a2 2 0 01-2 2h-4"/><polyline points="10 17 15 12 10 7"/><line x1="15" y1="12" x2="3" y2="12"/></svg>管理员登录</button></div></aside><div class="main"><div class="groups-container" id="gC"><?php foreach($data['groups'] as $gi=>$g):?><div class="group gc-<?=$gi%6?>" id="g-<?=esc($g['id'])?>"><div class="group-header"><div class="group-title-wrap"><div class="group-icon"><?=esc($g['emoji'])?></div><div class="group-title"><?=esc($g['name'])?></div></div><div class="group-actions admin-only"><button onclick="oBM('<?=esc($g['id'])?>')" title="添加网站"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg></button><button onclick="oGM('<?=esc($g['id'])?>')" title="编辑分组"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M11 4H4a2 2 0 00-2 2v14a2 2 0 002 2h14a2 2 0 002-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 013 3L12 15l-4 1 1-4 9.5-9.5z"/></svg></button><button onclick="cDG('<?=esc($g['id'])?>')" title="删除分组"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="3 6 5 6 21 6"/><path d="M19 6v14a2 2 0 01-2 2H7a2 2 0 01-2-2V6m3 0V4a2 2 0 012-2h4a2 2 0 012 2v2"/></svg></button></div></div><div class="bookmarks-grid"><?php foreach($g['bookmarks'] as $bm):?><a class="bookmark-card" href="<?=esc($bm['url'])?>" target="_blank" rel="noopener"><button class="bookmark-edit admin-only" onclick="event.preventDefault();oBM('<?=esc($g['id'])?>','<?=esc($bm['id'])?>')" title="编辑"><svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3"><path d="M11 4H4a2 2 0 00-2 2v14a2 2 0 002 2h14a2 2 0 002-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 013 3L12 15l-4 1 1-4 9.5-9.5z"/></svg></button><button class="bookmark-delete admin-only" onclick="event.preventDefault();cDB('<?=esc($g['id'])?>','<?=esc($bm['id'])?>')" title="删除"><svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg></button><div class="bm-row1"><div class="bookmark-favicon" data-url="<?=esc($bm['url'])?>"><img src="<?=esc($bm['favicon']??'https://t0.gstatic.cn/faviconV2?client=SOCIAL&type=FAVICON&fallback_opts=TYPE,SIZE,URL&url=http://'.getDomain($bm['url']).'&size=32')?>" alt="" loading="lazy" onerror="tnF(this)"></div><div class="bookmark-name"><?=esc($bm['name'])?></div></div><?php if(!empty($bm['desc'])):?><div class="bookmark-desc"><?=esc($bm['desc'])?></div><?php endif;?></a><?php endforeach;?></div></div><?php endforeach;?><?php if(empty($data['groups'])&&$adminMode):?><p style="color:var(--text-muted);text-align:center;padding:40px">暂无分组，点击左侧"添加分组"开始</p><?php endif;?></div><footer class="site-footer">Copyright &copy; <a href="https://www.5iehome.cc" target="_blank">E家分享</a></footer></div></div><div class="modal-overlay" id="bmM"><div class="modal"><h2 id="bmMT">添加书签</h2><div class="form-group"><label>网址</label><div class="input-row"><input type="url" id="bmU" placeholder="https://example.com" oninput="onUI()"><button class="fetch-btn" id="fB" onclick="fSI()">自动获取</button></div><div class="input-hint">输入网址后点击"自动获取"</div></div><div class="form-group"><label>名称</label><input type="text" id="bmN" placeholder="网站名称" maxlength="40"></div><div class="form-group"><label>描述</label><input type="text" id="bmD" placeholder="网站描述（可选）" maxlength="40"></div><div class="form-group"><label>图标地址</label><div class="input-row"><input type="url" id="bmF" placeholder="自动获取或手动输入" oninput="onFI()"><button class="fetch-btn" id="rFB" onclick="rFv()">重置</button></div><div class="input-hint">留空则自动抓取，也可粘贴自定义图标链接</div></div><div class="form-group"><label>预览</label><div class="favicon-preview" id="fP"><span style="color:var(--text-muted)">输入网址后自动获取</span></div></div><div class="modal-actions"><button class="btn btn-secondary" onclick="cM('bmM')">取消</button><button class="btn btn-primary" onclick="sBm()">保存</button></div></div></div><div class="modal-overlay" id="gM"><div class="modal"><h2 id="gMT">添加分组</h2><div class="form-group"><label>分组名称</label><input type="text" id="gN" placeholder="例如：常用工具"></div><div class="form-group"><label>图标</label><div class="emoji-picker" id="eP"></div></div><div class="modal-actions"><button class="btn btn-secondary" onclick="cM('gM')">取消</button><button class="btn btn-primary" onclick="sGp()">保存</button></div></div></div><div class="modal-overlay" id="cM"><div class="modal"><h2>确认删除</h2><p id="cMsg" style="color:var(--text-secondary);margin-bottom:20px"></p><div class="modal-actions"><button class="btn btn-secondary" onclick="cM('cM')">取消</button><button class="btn btn-danger" id="cBtn">删除</button></div></div></div><div class="modal-overlay" id="lM"><div class="modal"><h2>管理员登录</h2><div class="form-group"><label>管理密码</label><input type="password" id="lP" placeholder="请输入管理密码" onkeydown="if(event.key==='Enter')dL()"></div><div class="modal-actions"><button class="btn btn-secondary" onclick="cM('lM')">取消</button><button class="btn btn-primary" onclick="dL()">登录</button></div></div></div><div class="modal-overlay" id="exportM"><div class="modal"><h2>数据导出</h2><div class="form-group"><label>选择导出格式：</label><div class="export-options"><label class="export-option"><input type="radio" name="exportFormat" value="html" checked><div class="export-info"><div class="export-title">Bookmarks (.html)</div><div class="export-desc">浏览器收藏夹兼容格式，仅包含导航模块数据</div></div></label><label class="export-option"><input type="radio" name="exportFormat" value="json"><div class="export-info"><div class="export-title">JSON数据 (.json)</div><div class="export-desc">完整的备份数据，包含链接备注及所有模块类型的数据</div></div></label></div></div><div class="modal-actions"><button class="btn btn-secondary" onclick="cM('exportM')">取消</button><button class="btn btn-primary" onclick="doExport()">开始导出</button></div><div class="export-limit" style="text-align:right">每次操作将刷新页面以更新数据</div></div></div><div class="toast" id="tst"></div><script>
const E=['📌','','🎮','📚','💼','🎨','🎵','🌍','💡','🔥','⭐','','📱','💻','🏠','❤️','🎯','🔑','☁️','📧','🛒','📷','🎬','🔬','📝','🎪','🌈','🏆','🤖','🧠','🧩','⚡','🛡️','🌐','📊','🎙️','💬','🧪','','🧭','🏛️','','⚙️','🪄','🗂️','🧬','🤝','💰'],TK='starnav_theme',BK='starnav_bg_image',BT='starnav_bg_theme',CP='starnav_cache_',CE=604800000;
let eB=null,eG=null,sE='📌',aG=null;
const gD=u=>{try{return new URL(u).hostname.replace(/^www\./,'')}catch(e){return u}};
const gFU=u=>{try{const d=gD(u);return`https://t0.gstatic.cn/faviconV2?client=SOCIAL&type=FAVICON&fallback_opts=TYPE,SIZE,URL&url=http://${d}&size=32`}catch(e){return''}};
const gFF=u=>{try{const d=gD(u);return[`https://t0.gstatic.cn/faviconV2?client=SOCIAL&type=FAVICON&fallback_opts=TYPE,SIZE,URL&url=http://${d}&size=32`,`https://ico.kucat.cn/get.php?url=${u}`,`https://icon.horse/icon/${d}`]}catch(e){return[]}};
function tnF(i){const c=i.parentElement,u=c.dataset.url;if(!u||!u.startsWith('http')){c.innerHTML='<span class="fallback-icon">🔗</span>';return}const f=gFF(u),s=parseInt(i.dataset.s||'0'),n=s+1;if(n<f.length){i.dataset.s=n;i.src=f[n]}else{c.innerHTML='<span class="fallback-icon">🔗</span>'}}
async function hP(p){const d=new TextEncoder().encode(p+'_starnav_salt_2024'),h=await crypto.subtle.digest('SHA-256',d);return Array.from(new Uint8Array(h)).map(b=>b.toString(16).padStart(2,'0')).join('')}
function oLM(){document.getElementById('lP').value='';document.getElementById('lM').classList.add('show');setTimeout(()=>document.getElementById('lP').focus(),100)}
async function dL(){const p=document.getElementById('lP').value;if(!p){sT('请输入密码','error');return}const h=await hP(p),f=new FormData();f.append('action','login');f.append('password',h);try{const r=await fetch('nav-api.php',{method:'POST',body:f}),j=await r.json();if(j.success){cM('lM');sT('登录成功','success');setTimeout(()=>location.reload(),500)}else sT('密码错误','error')}catch(e){sT('登录失败','error')}}
function rC(){const n=new Date(),h=String(n.getHours()).padStart(2,'0'),m=String(n.getMinutes()).padStart(2,'0');document.getElementById('clk').textContent=`${h}:${m}`;const w=['日','一','二','三','四','五','六'];document.getElementById('clkD').textContent=`${n.getFullYear()}年${n.getMonth()+1}月${n.getDate()}日 星期${w[n.getDay()]}`}
function uFP(u){const p=document.getElementById('fP');if(u)p.innerHTML=`<img src="${u}" alt="" onerror="this.style.display='none'"><span style="display:none;color:var(--text-muted)">无法加载</span>`}
async function fSI(){const i=document.getElementById('bmU');let u=i.value.trim();if(!u)return;if(!/^https?:\/\//i.test(u)){u='https://'+u;i.value=u}const b=document.getElementById('fB'),d=gD(u);b.disabled=true;b.innerHTML='<span class="loading-spinner"></span>';uFP(gFU(u));const c=localStorage.getItem(CP+d);if(c){try{const j=JSON.parse(c);if(Date.now()-j.timestamp<CE&&j.title){document.getElementById('bmN').value=j.title;if(j.favicon)uFP(j.favicon);b.disabled=false;b.textContent='自动获取';return}}catch(e){}}const px=[`https://api.allorigins.win/raw?url=`,`https://corsproxy.io/?url=`,`https://api.codetabs.com/v1/proxy?quest=`];let bh='';const rs=await Promise.allSettled(px.map(async p=>{try{const r=await fetch(p+encodeURIComponent(u),{signal:AbortSignal.timeout(8000),headers:{'Accept':'text/html','Accept-Language':'zh-CN,zh;q=0.9'}});if(r.ok){const t=await r.text();if(t.length>100)return t}}catch(e){}return''}));for(const r of rs)if(r.status==='fulfilled'&&r.value&&r.value.length>bh.length)bh=r.value;let t='',fv='';if(bh.length>100){const ur=new URL(u),p=new DOMParser().parseFromString(bh,'text/html');for(const s of['link[rel="icon"][type="image/svg+xml"]','link[rel="icon"][sizes="192x192"]','link[rel="apple-touch-icon"]','link[rel="icon"]']){const el=p.querySelector(s);if(el&&el.getAttribute('href')){let h=el.getAttribute('href');if(h.startsWith('//'))h='https:'+h;else if(h.startsWith('/'))h=ur.origin+h;else if(!h.startsWith('http'))h=ur.origin+'/'+h;fv=h;break}}t=(p.querySelector('meta[property="og:site_name"]')?.content||p.querySelector('meta[property="og:title"]')?.content||p.querySelector('title')?.textContent||'').trim().replace(/\s+/g,' ');const fi=document.getElementById('bmF').value.trim();if(fv&&!fi){uFP(fv)}else if(fi){uFP(fi)}try{localStorage.setItem(CP+d,JSON.stringify({title:t,favicon:fv,timestamp:Date.now()}))}catch(e){}}document.getElementById('bmN').value=t||d;b.disabled=false;b.textContent='自动获取'}
let fT=null;
function onFI(){const v=document.getElementById('bmF').value.trim();if(v){if(/\.(png|ico|svg|jpg|jpeg|webp|gif)$/i.test(v)){uFP(v)}else if(/^https?:\/\//i.test(v)){uFP(gFU(v))}else{uFP(v)}}else{const u=document.getElementById('bmU').value.trim();if(u&&/^https?:\/\//i.test(u))uFP(gFU(u))}}
function onUI(){clearTimeout(fT);const u=document.getElementById('bmU').value.trim();const fi=document.getElementById('bmF').value.trim();if(u&&/^https?:\/\//i.test(u)&&!fi)uFP(gFU(u));fT=setTimeout(()=>{if(u.length>5&&fi.length===0)fSI()},1200)}
function rFv(){const u=document.getElementById('bmU').value.trim();if(!u){document.getElementById('bmF').value='';document.getElementById('fP').innerHTML='<span style="color:var(--text-muted)">输入网址后自动获取</span>';return}document.getElementById('bmF').value='';uFP(gFU(u))}
function oBM(gid,bid){eB={groupId:gid,bookmarkId:bid||null};if(bid){fetch(`nav-api.php?action=getBookmark&groupId=${encodeURIComponent(gid)}&bookmarkId=${encodeURIComponent(bid)}`).then(r=>r.json()).then(bm=>{document.getElementById('bmMT').textContent='编辑书签';document.getElementById('bmU').value=bm.url;document.getElementById('bmN').value=bm.name;document.getElementById('bmD').value=bm.desc||'';let fv=bm.favicon||'';if(fv&&/^https?:\/\//i.test(fv)&&!/\.(png|ico|svg|jpg|jpeg|webp|gif)$/i.test(fv))fv=gFU(fv);document.getElementById('bmF').value=fv;uFP(fv||gFU(bm.url));document.getElementById('bmM').classList.add('show');setTimeout(()=>document.getElementById('bmU').focus(),100)})}else{document.getElementById('bmMT').textContent='添加书签';document.getElementById('bmU').value='';document.getElementById('bmN').value='';document.getElementById('bmD').value='';document.getElementById('bmF').value='';document.getElementById('fP').innerHTML='<span style="color:var(--text-muted)">输入网址后自动获取</span>';document.getElementById('bmM').classList.add('show');setTimeout(()=>document.getElementById('bmU').focus(),100)}}
async function sBm(){const u=document.getElementById('bmU').value.trim(),n=document.getElementById('bmN').value.trim(),d=document.getElementById('bmD').value.trim(),cf=document.getElementById('bmF').value.trim();if(!u||!n){sT('请输入网址和名称','error');return}const fu=/^https?:\/\//i.test(u)?u:'https://'+u;let fv=cf;if(fv&&/^https?:\/\//i.test(fv)&&!/\.(png|ico|svg|jpg|jpeg|webp|gif)$/i.test(fv))fv=gFU(fv);if(!fv)fv=gFU(fu);const f=new FormData();f.append('action','saveBookmark');f.append('groupId',eB.groupId);f.append('bookmarkId',eB.bookmarkId||'');f.append('url',fu);f.append('name',n);f.append('desc',d);f.append('favicon',fv);try{const r=await fetch('nav-api.php',{method:'POST',body:f}),j=await r.json();if(j.success){cM('bmM');sT(eB.bookmarkId?'书签已更新':'书签已添加','success');setTimeout(()=>location.reload(),500)}else sT('保存失败','error')}catch(e){sT('保存失败','error')}}
function oGM(gid){eG=gid||null;rEP();if(gid){fetch(`nav-api.php?action=getGroup&groupId=${encodeURIComponent(gid)}`).then(r=>r.json()).then(g=>{document.getElementById('gMT').textContent='编辑分组';document.getElementById('gN').value=g.name;sE=g.emoji;rEP();document.getElementById('gM').classList.add('show');setTimeout(()=>document.getElementById('gN').focus(),100)})}else{document.getElementById('gMT').textContent='添加分组';document.getElementById('gN').value='';sE='📌';rEP();document.getElementById('gM').classList.add('show');setTimeout(()=>document.getElementById('gN').focus(),100)}}
function rEP(){document.getElementById('eP').innerHTML=E.map(e=>`<button class="emoji-option ${e===sE?'active':''}" onclick="sE='${e}';rEP()">${e}</button>`).join('')}
async function sGp(){const n=document.getElementById('gN').value.trim();if(!n){sT('请输入分组名称','error');return}const f=new FormData();f.append('action','saveGroup');f.append('groupId',eG||'');f.append('name',n);f.append('emoji',sE);try{const r=await fetch('nav-api.php',{method:'POST',body:f}),j=await r.json();if(j.success){cM('gM');sT(eG?'分组已更新':'分组已添加','success');setTimeout(()=>location.reload(),500)}else sT('保存失败','error')}catch(e){sT('保存失败','error')}}
function cDG(id){const n=prompt('确认删除分组？输入分组名确认：');if(!n)return;fetch(`nav-api.php?action=getGroup&groupId=${encodeURIComponent(id)}`).then(r=>r.json()).then(g=>{if(g.name===n){const f=new FormData();f.append('action','deleteGroup');f.append('groupId',id);fetch('nav-api.php',{method:'POST',body:f}).then(r=>r.json()).then(j=>{if(j.success){sT('分组已删除','success');setTimeout(()=>location.reload(),500)}else sT('删除失败','error')})}else sT('分组名不匹配','error')})}
function cDB(g,b){fetch(`nav-api.php?action=getBookmark&groupId=${encodeURIComponent(g)}&bookmarkId=${encodeURIComponent(b)}`).then(r=>r.json()).then(bm=>{if(confirm(`确定要删除书签"${bm.name}"吗？`)){const f=new FormData();f.append('action','deleteBookmark');f.append('groupId',g);f.append('bookmarkId',b);fetch('nav-api.php',{method:'POST',body:f}).then(r=>r.json()).then(j=>{if(j.success){sT('书签已删除','success');setTimeout(()=>location.reload(),500)}else sT('删除失败','error')})}})}
function tT(){const h=document.documentElement,c=h.getAttribute('data-theme'),n=c==='dark'?'light':'dark';h.setAttribute('data-theme',n);localStorage.setItem(TK,n);uTL();uBg()}
function uTL(){document.getElementById('tL').textContent=document.documentElement.getAttribute('data-theme')==='dark'?'日间模式':'夜间模式'}
function iT(){const s=localStorage.getItem(TK);if(s)document.documentElement.setAttribute('data-theme',s);else document.documentElement.setAttribute('data-theme',window.matchMedia('(prefers-color-scheme:light)').matches?'light':'dark');uTL()}
const BTM=[{n:'乡村',d:'Studio Ghibli anime style, bright sunny countryside landscape, rolling green hills with wildflowers, fluffy white clouds in blue sky, peaceful rural scenery, watercolor painting, soft warm lighting, vibrant colors',ni:'Studio Ghibli anime style, starry night sky with crescent moon, quiet Japanese village with warm lights, soft moonlight reflecting on river, fireflies glowing in the dark, dark blue purple atmosphere, watercolor painting, dreamy and peaceful'},{n:'海洋',d:'Studio Ghibli anime style, bright seaside cliff overlooking turquoise ocean, gentle waves crashing on rocks, seagulls flying, lighthouse in distance, clear blue sky, watercolor painting, warm sunlight, peaceful coastal scenery',ni:'Studio Ghibli anime style, moonlit ocean at night, silver moonlight path on calm water, distant lighthouse beam, stars reflected on sea surface, bioluminescent plankton glowing on shore, dark blue ocean, watercolor painting, serene and mystical'},{n:'森林',d:'Studio Ghibli anime style, enchanted forest with sunlight filtering through tall ancient trees, mossy ground with mushrooms and small flowers, gentle stream, butterflies and forest spirits, watercolor painting, dappled light, lush green',ni:'Studio Ghibli anime style, mystical forest at night, glowing fireflies among ancient trees, bioluminescent mushrooms on forest floor, moonlight through canopy, small forest spirits with lanterns, deep blue emerald atmosphere, watercolor painting, magical and tranquil'},{n:'天空',d:'Studio Ghibli anime style, floating islands in bright blue sky, waterfalls cascading from clouds, airships sailing between peaks, lush gardens on floating rocks, cotton candy clouds, golden sunlight, watercolor painting, adventurous and whimsical',ni:'Studio Ghibli anime style, floating islands under starlit sky, aurora borealis over cloud cities, glowing crystals on floating rocks, airship with warm cabin lights, shooting stars, deep purple teal atmosphere, watercolor painting, dreamli[... 17 chars omitted ...]
const BA='https://trae-api-cn.mchost.guru/api/ide/v1/text_to_image';
const gBT=()=>{const i=parseInt(localStorage.getItem(BT));return isNaN(i)||i<0||i>=BTM.length?0:i};
const isBA=()=>localStorage.getItem(BK)==='true';
const gBI=d=>{const t=BTM[gBT()];return BA+'?prompt='+encodeURIComponent(d?t.ni:t.d)+'&image_size=landscape_16_9'};
function tBg(){if(isBA()){localStorage.setItem(BK,'false');document.body.classList.remove('bg-image-active');document.getElementById('bgG').classList.remove('active');document.getElementById('bgP').classList.remove('active');document.getElementById('bgTP').classList.remove('active');uBB()}else{localStorage.setItem(BK,'true');document.body.classList.add('bg-image-active');uBg(true);uBB()}}
function uBg(sl){const g=document.getElementById('bgG'),i=document.getElementById('bgI'),p=document.getElementById('bgP'),pi=document.getElementById('bgPI'),pl=document.getElementById('bgPL');if(!isBA()){g.classList.remove('active');p.classList.remove('active');return}const dk=document.documentElement.getAttribute('data-theme')==='dark',t=BTM[gBT()],u=gBI(dk);if(pl)pl.textContent=t.n+' · '+(dk?'夜间':'日间');document.getElementById('bgTP').classList.add('active');rBTP();if(sl){const b=document.getElementById('bgB');if(b)b.disabled=true;const l=document.getElementById('bgL');if(l)l.innerHTML='<span class="loading-spinner"></span>'}const im=new Image();im.onload=()=>{i.src=u;g.classList.add('active');pi.src=u;p.classList.add('active');if(sl){const b=document.getElementById('bgB');if(b)b.disabled=false;uBB()}};im.onerror=()=>{if(sl){const b=document.getElementById('bgB');if(b)b.disabled=false;uBB();sT('背景图加载失败','error')}};im.src=u}
function rBTP(){const c=document.getElementById('bgTO');if(!c)return;const ci=gBT();c.innerHTML=BTM.map((t,i)=>`<button class="bg-theme-opt${i===ci?' selected':''}" onclick="sBT(${i})">${t.n}</button>`).join('')}
function sBT(i){localStorage.setItem(BT,String(i));uBg(true);rBTP()}
function uBB(){const l=document.getElementById('bgL');if(!l)return;l.textContent=isBA()?'关闭':'背景';const b=document.getElementById('bgB');if(b)b.style.color=isBA()?'var(--accent-light)':''}
function sG(id){aG=id;const e=document.getElementById('g-'+id);if(e)e.scrollIntoView({behavior:'smooth',block:'start'})}
function cM(id){document.getElementById(id).classList.remove('show')}
function sT(m,t=''){const e=document.getElementById('tst');e.textContent=m;e.className='toast'+(t?' '+t:'');requestAnimationFrame(()=>e.classList.add('show'));setTimeout(()=>e.classList.remove('show'),2500)}
let dragGroup=null;
function initDrag(){if(!document.body.classList.contains('admin-mode'))return;const groups=document.querySelectorAll('.group');groups.forEach(g=>{g.setAttribute('draggable',true);g.addEventListener('dragstart',onDragStart);g.addEventListener('dragover',onDragOver);g.addEventListener('dragenter',onDragEnter);g.addEventListener('dragleave',onDragLeave);g.addEventListener('drop',onDrop);g.addEventListener('dragend',onDragEnd)})}
function onDragStart(e){dragGroup=e.currentTarget;e.currentTarget.classList.add('dragging');e.dataTransfer.effectAllowed='move';e.dataTransfer.setData('text/plain','')}
function onDragOver(e){e.preventDefault();e.dataTransfer.dropEffect='move'}
function onDragEnter(e){e.preventDefault();const t=e.currentTarget;if(t!==dragGroup)t.classList.add('drag-over')}
function onDragLeave(e){e.currentTarget.classList.remove('drag-over')}
function onDrop(e){e.preventDefault();const t=e.currentTarget;t.classList.remove('drag-over');if(t===dragGroup)return;const c=document.getElementById('gC'),all=[...c.querySelectorAll('.group')],fi=all.indexOf(dragGroup),ti=all.indexOf(t);if(fi<ti)c.insertBefore(dragGroup,t.nextSibling);else c.insertBefore(dragGroup,t);sGOrder()}
function onDragEnd(e){e.currentTarget.classList.remove('dragging');dragGroup=null;document.querySelectorAll('.drag-over').forEach(x=>x.classList.remove('drag-over'))}
function sGOrder(){const order=[...document.querySelectorAll('.group')].map(g=>g.id.replace('g-',''));const f=new FormData();f.append('action','reorderGroups');f.append('order',JSON.stringify(order));fetch('nav-api.php',{method:'POST',body:f}).then(r=>r.json()).then(j=>{if(j.success)sT('分组顺序已保存','success');else sT('保存顺序失败','error')}).catch(()=>sT('保存顺序失败','error'))}
function oEM(){document.getElementById('exportM').classList.add('show')}
function doExport(){const f=document.querySelector('input[name="exportFormat"]:checked').value;if(f==='json'){fetch('nav-api.php?action=exportJSON').then(r=>r.blob()).then(b=>{const u=URL.createObjectURL(b),a=document.createElement('a');a.href=u;a.download='starnav-backup.json';a.click();URL.revokeObjectURL(u);cM('exportM');sT('JSON导出成功','success')}).catch(()=>sT('导出失败','error'))}else{fetch('nav-api.php?action=exportHTML').then(r=>r.blob()).then(b=>{const u=URL.createObjectURL(b),a=document.createElement('a');a.href=u;a.download='starnav-bookmarks.html';a.click();URL.revokeObjectURL(u);cM('exportM');sT('HTML导出成功','success')}).catch(()=>sT('导出失败','error'))}}
document.querySelectorAll('.modal-overlay').forEach(o=>o.addEventListener('click',e=>{if(e.target===o)o.classList.remove('show')}));
document.addEventListener('keydown',e=>{if(e.key==='Escape')document.querySelectorAll('.modal-overlay.show').forEach(m=>m.classList.remove('show'))});
iT();if(isBA())document.body.classList.add('bg-image-active');uBB();
setInterval(rC,1000);rC();
initDrag();
</script></body></html>
